"""Tests for fail-fast behavior when config is missing."""

from pathlib import Path

import pytest

import agentpulse.config as config


def test_from_config_raises_when_file_missing(tmp_path: Path) -> None:
    missing = tmp_path / "nonexistent.json"

    with pytest.raises(FileNotFoundError) as exc:
        config.Settings.from_config(config_path=missing)

    assert str(missing) in str(exc.value)


def test_service_main_exits_with_helpful_message(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
    capsys: pytest.CaptureFixture,
) -> None:
    from agentpulse import __main__ as entry

    missing = tmp_path / "missing.json"
    config.reset_settings()
    monkeypatch.setattr("sys.argv", ["agentpulse", "--config", str(missing)])

    with pytest.raises(SystemExit) as exc:
        entry.main()

    assert exc.value.code == 1
    captured = capsys.readouterr()
    err = captured.err + captured.out
    assert "config not found" in err.lower()
    assert "agentpulse init" in err
